import { Component } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';

@Component({ selector: 'app-login', templateUrl: './login.component.html' })
export class LoginComponent {
  email = '';
  password = '';
  loading = false;
  error = '';
  showPassword = false;

  credentials = [
    { role: 'Project Manager', email: 'projectmanager@mail.com', pass: 'projectmanager123', color: '#a78bfa' },
    { role: 'Dev Dept Head', email: 'development@mail.com', pass: 'development123', color: '#60a5fa' },
    { role: 'Backend Lead', email: 'teamleadbackend@mail.com', pass: 'teamleadbackend123', color: '#fbbf24' },
    { role: 'Employee', email: 'john.doe@mail.com', pass: 'employee123', color: '#94a3b8' },
  ];

  constructor(private auth: AuthService, private router: Router) {
    if (this.auth.isLoggedIn) this.router.navigate(['/dashboard']);
  }

  fill(email: string, pass: string): void { this.email = email; this.password = pass; }

  login(): void {
    if (!this.email || !this.password) { this.error = 'Please enter email and password.'; return; }
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(this.email)) { this.error = 'Invalid email format.'; return; }
    this.loading = true; this.error = '';
    this.auth.login(this.email, this.password).subscribe({
      next: r => { this.loading = false; if (r.success) this.router.navigate(['/dashboard']); else this.error = r.message; },
      error: e => { this.loading = false; this.error = e.error?.message || 'Invalid credentials'; }
    });
  }
}
<div style="min-height:100vh;display:flex;align-items:center;justify-content:center;background:var(--bg);padding:20px">
  <div style="width:100%;max-width:420px">
    <div style="text-align:center;margin-bottom:32px">
      <a routerLink="/" style="display:inline-block;margin-bottom:12px;font-size:13px;color:var(--text-muted);text-decoration:none;">&larr; Back to Home</a>
      <br/>
      <div style="display:inline-flex;align-items:center;justify-content:center;width:64px;height:52px;background:var(--accent);border-radius:14px;font-size:22px;color:white;font-weight:800;margin-bottom:14px;letter-spacing:1px">ITA</div>
      <div style="font-size:22px;font-weight:800;color:var(--text-primary);letter-spacing:-0.5px">Intelligent Task Allocator</div>
      <div style="font-size:13px;color:var(--text-muted);margin-top:4px">Enterprise Task Management System</div>
    </div>

    <div class="card">
      <div class="card-body">
        <div *ngIf="error" style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.2);border-radius:6px;padding:10px 14px;margin-bottom:16px;font-size:13px;color:var(--danger)">{{ error }}</div>

        <div class="form-group">
          <label class="form-label">Email</label>
          <input type="email" class="form-control" name="email" placeholder="you@company.com" [(ngModel)]="email" #emailCtrl="ngModel" (keyup.enter)="login()" required pattern="^[^\s@]+@[^\s@]+\.[^\s@]+$">
          <div *ngIf="emailCtrl.invalid && (emailCtrl.dirty || emailCtrl.touched)" style="color:var(--danger);font-size:12px;margin-top:4px">
            <span *ngIf="emailCtrl.errors?.['required']">Email is required.</span>
            <span *ngIf="emailCtrl.errors?.['pattern']">Invalid email format.</span>
          </div>
        </div>
        <div class="form-group">
          <label class="form-label">Password</label>
          <div style="position:relative">
            <input [type]="showPassword ? 'text' : 'password'" class="form-control" name="password" placeholder="••••••••" [(ngModel)]="password" #passwordCtrl="ngModel" (keyup.enter)="login()" required style="padding-right: 40px;">
            <button type="button" (click)="showPassword = !showPassword" style="position:absolute;right:10px;top:50%;transform:translateY(-50%);background:none;border:none;cursor:pointer;color:var(--text-muted);font-size:16px;padding:0;outline:none;" title="Toggle Password Visibility">
              <span *ngIf="showPassword">🙈</span>
              <span *ngIf="!showPassword">👁️</span>
            </button>
          </div>
          <div *ngIf="passwordCtrl.invalid && (passwordCtrl.dirty || passwordCtrl.touched)" style="color:var(--danger);font-size:12px;margin-top:4px">
            <span *ngIf="passwordCtrl.errors?.['required']">Password is required.</span>
          </div>
        </div>

        <button class="btn btn-primary w-full" style="justify-content:center;margin-top:8px" (click)="login()" [disabled]="loading">
          {{ loading ? 'Signing in...' : 'Sign In' }}
        </button>

        <div style="text-align:center;margin-top:16px;font-size:13px;color:var(--text-muted)">
          New here? <a routerLink="/register" style="color:var(--accent);font-weight:600;margin-left:4px">Create an account</a>
        </div>
      </div>
    </div>

    <!-- Demo credentials -->
    <div style="margin-top:20px;background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius);padding:14px 16px">
      <div style="font-size:11px;font-weight:700;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:10px">Quick Demo Login</div>
      <div style="display:flex;flex-direction:column;gap:6px">
        <div *ngFor="let cred of credentials"
          (click)="fill(cred.email, cred.pass)"
          style="display:flex;align-items:center;justify-content:space-between;padding:6px 10px;border-radius:6px;cursor:pointer;border:1px solid transparent;transition:all 0.15s"
          [style.borderColor]="email === cred.email ? 'var(--accent)' : 'transparent'"
          [style.background]="email === cred.email ? 'var(--accent-subtle)' : 'var(--bg-hover)'">
          <div>
            <div style="font-size:12px;font-weight:600;" [style.color]="cred.color">{{ cred.role }}</div>
            <div style="font-size:11px;color:var(--text-muted);font-family:'DM Mono',monospace">{{ cred.email }}</div>
          </div>
          <span style="font-size:11px;color:var(--text-muted)">click to fill →</span>
        </div>
      </div>
    </div>
  </div>
</div>
